### 3. Component Registry Pattern (Safe Rendering)

Create a **registry** of pre-approved components:

```typescript
// lib/templates/registry.ts

import { HeroFullImage } from '@/components/templates/heroes/HeroFullImage';
import { HeroMinimal } from '@/components/templates/heroes/HeroMinimal';
import { HeroSplit } from '@/components/templates/heroes/HeroSplit';

import { PortfolioMasonry } from '@/components/templates/portfolio/PortfolioMasonry';
import { PortfolioCarousel } from '@/components/templates/portfolio/PortfolioCarousel';
import { PortfolioGrid } from '@/components/templates/portfolio/PortfolioGrid';

import { ContactSticky } from '@/components/templates/contact/ContactSticky';
import { ContactSimple } from '@/components/templates/contact/ContactSimple';

// REGISTRY: Map string keys to actual components
export const COMPONENT_REGISTRY = {
  // Heroes
  'hero-full-image': HeroFullImage,
  'hero-minimal': HeroMinimal,
  'hero-split': HeroSplit,

  // Portfolio
  'portfolio-masonry': PortfolioMasonry,
  'portfolio-carousel': PortfolioCarousel,
  'portfolio-grid': PortfolioGrid,

  // Contact
  'contact-sticky': ContactSticky,
  'contact-simple': ContactSimple,

  // Add more as needed
} as const;

export type ComponentKey = keyof typeof COMPONENT_REGISTRY;

// Type-safe component renderer
export function renderTemplateComponent(
  componentKey: string,
  props: Record<string, any>,
  config: TemplateConfig
) {
  const Component = COMPONENT_REGISTRY[componentKey as ComponentKey];

  if (!Component) {
    console.warn(`Component "${componentKey}" not found in registry`);
    return null;
  }

  return <Component {...props} config={config} />;
}
```

---

### 4. Dynamic Template Renderer

```typescript
// components/templates/TemplateRenderer.tsx

'use client';

import { useEffect, useState } from 'react';
import { renderTemplateComponent } from '@/lib/templates/registry';
import type { TemplateConfig } from '@/lib/types/templates';

interface TemplateRendererProps {
  templateId: string;
  professionalData: any;
}

export function TemplateRenderer({ templateId, professionalData }: TemplateRendererProps) {
  const [config, setConfig] = useState<TemplateConfig | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch template config from Supabase
    async function loadTemplate() {
      const { data, error } = await supabase
        .from('template_presets')
        .select('config')
        .eq('id', templateId)
        .eq('is_approved', true)
        .single();

      if (data) {
        setConfig(data.config);
      }
      setLoading(false);
    }

    loadTemplate();
  }, [templateId]);

  if (loading) {
    return <TemplateSkeleton />;
  }

  if (!config) {
    return <DefaultProfile professionalData={professionalData} />;
  }

  return (
    <div 
      className="template-container"
      style={{
        '--color-primary': config.colors.primary,
        '--color-secondary': config.colors.secondary,
        '--font-heading': config.typography.headingFont,
        '--font-body': config.typography.bodyFont,
      } as React.CSSProperties}
    >
      {/* Render sections based on config */}

      {/* Hero Section */}
      {renderTemplateComponent(
        `hero-${config.layout.hero.variant}`,
        { 
          professional: professionalData,
          showTagline: config.layout.hero.showTagline 
        },
        config
      )}

      {/* Portfolio Section */}
      {renderTemplateComponent(
        `portfolio-${config.layout.portfolio.variant}`,
        { 
          projects: professionalData.projects,
          columns: config.layout.portfolio.columns 
        },
        config
      )}

      {/* About Section */}
      {config.layout.about && renderTemplateComponent(
        `about-${config.layout.about.variant}`,
        { 
          bio: professionalData.bio,
          values: professionalData.values 
        },
        config
      )}

      {/* Contact Section */}
      {renderTemplateComponent(
        `contact-${config.layout.contact.variant}`,
        { 
          professional: professionalData,
          whatsappProminent: config.layout.contact.whatsappProminent 
        },
        config
      )}
    </div>
  );
}
```

---

### 5. Africa-First Optimizations

```typescript
// lib/templates/africa-optimizer.ts

export function optimizeTemplateForAfrica(config: TemplateConfig, connectionType: '2g' | '3g' | '4g') {
  const optimized = { ...config };

  if (connectionType === '2g' || connectionType === '3g') {
    // Low-data mode
    optimized.features.lowDataMode = true;
    optimized.layout.portfolio.columns = 1; // Single column
    optimized.layout.hero.variant = 'minimal'; // No heavy images
    optimized.africa.imageCompression = 'maximum';
    optimized.features.showGPSMap = false; // No maps
  }

  if (connectionType === '2g') {
    // Ultra-low mode
    optimized.typography.headingFont = 'system-ui'; // No custom fonts
    optimized.typography.bodyFont = 'system-ui';
    optimized.features.showRecommendations = false; // Defer non-essential
  }

  return optimized;
}

// Hook to detect connection quality
export function useConnectionQuality() {
  const [connectionType, setConnectionType] = useState<'2g' | '3g' | '4g'>('4g');

  useEffect(() => {
    if ('connection' in navigator) {
      const conn = (navigator as any).connection;
      const type = conn.effectiveType || '4g';
      setConnectionType(type);
    }
  }, []);

  return connectionType;
}
```

---

### 6. Server-Side Rendering (Critical for Africa)

```typescript
// app/pro/[slug]/page.tsx

export default async function ProfessionalProfile({ params }: { params: { slug: string } }) {
  // Fetch professional data (server-side)
  const professional = await getProfessionalWithProjects(params.slug);

  // Fetch template config (server-side, cached)
  const template = professional.template_id
    ? await getTemplateConfig(professional.template_id)
    : null;

  // Apply template config to generate CSS classes
  const cssVariables = template ? buildCSSVariables(template.config) : defaultVariables;

  return (
    <div 
      className="profile-container"
      style={cssVariables}
    >
      {/* Render pre-built components with server data */}
      <HeroSection 
        professional={professional}
        variant={template?.config.layout.hero.variant || 'full-image'}
      />

      <PortfolioSection 
        projects={professional.projects}
        variant={template?.config.layout.portfolio.variant || 'masonry'}
      />

      {/* ... more sections */}
    </div>
  );
}

// Helper to build CSS variables
function buildCSSVariables(config: TemplateConfig) {
  return {
    '--color-primary': config.colors.primary,
    '--color-secondary': config.colors.secondary,
    '--font-heading': config.typography.headingFont,
    '--font-body': config.typography.bodyFont,
  } as React.CSSProperties;
}
```

---

### 7. Template Submission (Designer Side)

```typescript
// app/pro/designer/submit-template/page.tsx

export default function SubmitTemplatePage() {
  const handleSubmit = async (formData: FormData) => {
    const config = {
      colors: {
        primary: formData.get('primary-color'),
        secondary: formData.get('secondary-color'),
        // ...
      },
      layout: {
        hero: {
          variant: formData.get('hero-variant'),
          // ...
        },
        // ...
      },
      // ... full config
    };

    // Validate config size (<10KB)
    const configSize = new Blob([JSON.stringify(config)]).size / 1024;
    if (configSize > 10) {
      throw new Error('Template config must be <10KB');
    }

    // Store in Supabase
    const { error } = await supabase
      .from('template_presets')
      .insert({
        name: formData.get('name'),
        designer_id: currentUser.id,
        config: config,
        price_xof: parseInt(formData.get('price')),
        is_approved: false, // Requires admin review
      });

    if (error) throw error;

    // Redirect to success
  };

  return (
    <form onSubmit={handleSubmit}>
      {/* Template builder UI */}
    </form>
  );
}
```

