// Cache template configs (reduce DB calls)
import { cache } from 'react';

export const getTemplateConfig = cache(async (templateId: string) => {
  const { data } = await supabase
    .from('template_presets')
    .select('config')
    .eq('id', templateId)
    .eq('is_approved', true)
    .single();

  return data?.config;
});

// Preload critical CSS
