### 4. Dynamic Template Renderer

```typescript
// components/templates/TemplateRenderer.tsx

'use client';

import { useEffect, useState } from 'react';
import { renderTemplateComponent } from '@/lib/templates/registry';
import type { TemplateConfig } from '@/lib/types/templates';

interface TemplateRendererProps {
  templateId: string;
  professionalData: any;
}

export function TemplateRenderer({ templateId, professionalData }: TemplateRendererProps) {
  const [config, setConfig] = useState<TemplateConfig | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Fetch template config from Supabase
    async function loadTemplate() {
      const { data, error } = await supabase
        .from('template_presets')
        .select('config')
        .eq('id', templateId)
        .eq('is_approved', true)
        .single();

      if (data) {
        setConfig(data.config);
      }
      setLoading(false);
    }

    loadTemplate();
  }, [templateId]);

  if (loading) {
    return <TemplateSkeleton />;
  }

  if (!config) {
    return <DefaultProfile professionalData={professionalData} />;
  }

  return (
    <div 
      className="template-container"
      style={{
        '--color-primary': config.colors.primary,
        '--color-secondary': config.colors.secondary,
        '--font-heading': config.typography.headingFont,
        '--font-body': config.typography.bodyFont,
      } as React.CSSProperties}
    >
      {/* Render sections based on config */}

      {/* Hero Section */}
      {renderTemplateComponent(
        `hero-${config.layout.hero.variant}`,
        { 
          professional: professionalData,
          showTagline: config.layout.hero.showTagline 
        },
        config
      )}

      {/* Portfolio Section */}
      {renderTemplateComponent(
        `portfolio-${config.layout.portfolio.variant}`,
        { 
          projects: professionalData.projects,
          columns: config.layout.portfolio.columns 
        },
        config
      )}

      {/* About Section */}
      {config.layout.about && renderTemplateComponent(
        `about-${config.layout.about.variant}`,
        { 
          bio: professionalData.bio,
          values: professionalData.values 
        },
        config
      )}

      {/* Contact Section */}
      {renderTemplateComponent(
        `contact-${config.layout.contact.variant}`,
        { 
          professional: professionalData,
          whatsappProminent: config.layout.contact.whatsappProminent 
        },
        config
      )}
    </div>
  );
}
