export function optimizeTemplateForAfrica(config: TemplateConfig, connectionType: '2g' | '3g' | '4g') {
  const optimized = { ...config };

  if (connectionType === '2g' || connectionType === '3g') {
    // Low-data mode
    optimized.features.lowDataMode = true;
    optimized.layout.portfolio.columns = 1; // Single column
    optimized.layout.hero.variant = 'minimal'; // No heavy images
    optimized.africa.imageCompression = 'maximum';
    optimized.features.showGPSMap = false; // No maps
  }

  if (connectionType === '2g') {
    // Ultra-low mode
    optimized.typography.headingFont = 'system-ui'; // No custom fonts
    optimized.typography.bodyFont = 'system-ui';
    optimized.features.showRecommendations = false; // Defer non-essential
  }

  return optimized;
}

